<template>
  <section id="Product">
    <v-container>
      <v-row class="text-center text-md-left">
        <v-col cols="12" md="6">
          <v-img
            max-height="400"
            max-width="400"
            contain
            class="d-flex align-end justify-center"
            :src="
              require('../../../assets/ecommerceTwo/' +
                'product image ' +
                currentImg +
                '.png')
            "
          >
            <v-container>
              <v-row
                class="row_media my-3 mx-auto white"
                justify="center"
                align="center"
                style="width: 80%"
              >
                <v-col v-for="n in 4" :key="n" cols="3">
                  <v-img
                    @click="currentImg = n"
                    style="cursor: pointer"
                    max-width="100"
                    max-height="100"
                    :src="
                      require('../../../assets/ecommerceTwo/product image ' +
                        n +
                        '.png')
                    "
                  ></v-img>
                </v-col>
              </v-row>
            </v-container>
          </v-img>
        </v-col>
        <v-col>
          <h1 class="text-h4 font-weight-black mb-2">{{ theProduct.title }}</h1>
          <p class="text-h6 grey--text">
            Men Olive Green & White Brand Logo Printed T-shirt
          </p>
          <h1>
            ${{ theProduct.price }} &nbsp;
            <del class="grey--text font-weight-light">{{
              Number(theProduct.price) + 10
            }}</del>
          </h1>
          <h2 class="font-weight-light my-4">SELECT SIZE</h2>
          <ul class="sizes mb-12">
            <v-btn
              class="mx-1"
              :color="item == activeSize ? 'secondary' : ''"
              fab
              @click="activeSize = item"
              v-for="(item, i) in sizes"
              :key="i"
              >{{ item }}</v-btn
            >
          </ul>
          <v-btn color="secondary" x-large class="mx-2 my-3 my-md-0">
            <span class="text-capitalize">add to cart</span>
            <v-icon right>mdi-cart-outline</v-icon>
          </v-btn>
          <v-btn outlined x-large>
            <span class="text-capitalize">add to wishlist</span>
            <v-icon right>mdi-heart-outline</v-icon>
          </v-btn>
        </v-col>
      </v-row>
    </v-container>
  </section>
</template>

<script>
import data from "@/db/data.json";
export default {
  data: () => ({
    items: data,
    itemId: "",
    theProduct: "",
    currentImg: 1,
    activeSize: "S",
    sizes: ["S", "M", "L", "XL", "XXL"],
    img: "",
  }),
  mounted() {
    this.itemdId = this.$route.params.id;
    let theProduct = this.items.products.find((item) => {
      return item.id === Number(this.itemdId);
    });
    this.theProduct = theProduct;
    if (this.theProduct.src) {
      this.img = this.theProduct.src;
    }
  },
};
</script>

